import { z } from 'zod';

const envSchema = z.object({
  JWT_SECRET: z.string().min(32),
  RATE_LIMIT_MAX: z.string().refine(value => !isNaN(Number(value)), 'Must be a number'),
  RATE_LIMIT_WINDOW: z.string().refine(value => !isNaN(Number(value)), 'Must be a number'),
});

export const env = envSchema.parse(process.env);

import { Request, Response } from 'express';
import { AuthService } from './auth.service';
import { RegisterDTO, LoginDTO } from './auth.dto';
import { authRegisterValidator, authLoginValidator } from './auth.validator';

export class AuthController {
  private authService: AuthService;

  constructor(authService: AuthService) {
    this.authService = authService;
  }

  public async register(req: Request, res: Response): Promise<void> {
    const validation = authRegisterValidator.safeParse(req.body);
    if (!validation.success) {
      res.status(400).json({ success: false, errors: validation.error.errors });
      return;
    }
    const registerDTO = validation.data as RegisterDTO;
    const user = await this.authService.register(registerDTO);
    res.status(201).json({ success: true, data: user });
  }

  public async login(req: Request, res: Response): Promise<void> {
    const validation = authLoginValidator.safeParse(req.body);
    if (!validation.success) {
      res.status(400).json({ success: false, errors: validation.error.errors });
      return;
    }
    const loginDTO = validation.data as LoginDTO;
    const token = await this.authService.login(loginDTO);
    res.status(200).json({ success: true, data: { token } });
  }
}

import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { UserRepository } from '../user/user.repository';
import { RegisterDTO, LoginDTO } from './auth.dto';
import { env } from '../../config/env';
import { AppError } from '../../utils/app-error';

export class AuthService {
  private userRepository: UserRepository;

  constructor(userRepository: UserRepository) {
    this.userRepository = userRepository;
  }

  public async register(registerDTO: RegisterDTO): Promise<any> {
    const existingUser = await this.userRepository.findOneByUsername(registerDTO.username);
    if (existingUser) {
      throw new AppError('Username already taken', 'USERNAME_TAKEN', 400);
    }
    const passwordHash = await bcrypt.hash(registerDTO.password, 10);
    const user = await this.userRepository.create({ ...registerDTO, passwordHash });
    return { id: user.id, username: user.username, email: user.email };
  }

  public async login(loginDTO: LoginDTO): Promise<string> {
    const user = await this.userRepository.findOneByUsername(loginDTO.username);
    if (!user || !(await bcrypt.compare(loginDTO.password, user.passwordHash))) {
      throw new AppError('Invalid credentials', 'INVALID_CREDENTIALS', 401);
    }
    return jwt.sign({ userId: user.id }, env.JWT_SECRET, { expiresIn: '1h' });
  }
}

export interface RegisterDTO {
  username: string;
  password: string;
  email: string;
}

export interface LoginDTO {
  username: string;
  password: string;
}

import { z } from 'zod';

export const authRegisterValidator = z.object({
  username: z.string().min(3).max(20),
  password: z.string().min(8),
  email: z.string().email(),
});

export const authLoginValidator = z.object({
  username: z.string().min(3).max(20),
  password: z.string().min(8),
});

import { UserModel } from './user.model';
import { User } from './user.interface';

export class UserRepository {
  public async findOneByUsername(username: string): Promise<User | null> {
    return UserModel.findOne({ username });
  }

  public async create(userDto: Partial<User>): Promise<User> {
    const user = new UserModel(userDto);
    return user.save();
  }
}

import mongoose, { Document } from 'mongoose';

export interface User extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const UserSchema = new mongoose.Schema({
  username: { type: String, required: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true },
  createdAt: { type: Date, default: Date.now },
});

export const UserModel = mongoose.model<User>('User', UserSchema);

export class AppError extends Error {
  statusCode: number;
  code: string;

  constructor(message: string, code: string, statusCode: number) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}
